fun solve(nums: Array<Long>): Long {
    val maxIndex = nums.size - 1
    val sieve = BooleanArray(maxIndex + 1) { true }.apply {
        this[0] = false
        this[1] = false
        for (i in 2..Math.sqrt(maxIndex.toDouble()).toInt()) {
            if (this[i]) {
                for (j in i * i..maxIndex step i) {
                    this[j] = false
                }
            }
        }
    }

    var sumA = 0L
    var sumB = 0L

    for (i in 0..maxIndex) {
        if (sieve[i]) {
            sumA += nums[i]
        } else {
            sumB += nums[i]
        }
    }

    return Math.abs(sumA - sumB)
}
```

